patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9ff1e3aa5502..04b5193c5524 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -5256,6 +5256,138 @@ Instruction *InstCombinerImpl::foldICmpBinOp(ICmpInst &I,
                           Constant::getNullValue(Op0->getType()), Op0);
   }

+
+  // icmp pred (op X, C), X --> icmp newPred X, newConst
+  // icmp pred X, (op X, C) --> icmp pred X, newConst
+  // where op is sdiv/udiv/lshr/ashr and C is a constant meeting the criteria.
+  {
+    const APInt *C;
+    // For sdiv: |C| > 1. Handles EQ/NE and signed predicates.
+    if ((ICmpInst::isSigned(Pred) || ICmpInst::isEquality(Pred)) &&
+        match(Op0, m_SDiv(m_Specific(Op1), m_APInt(C))) && C->abs().ugt(1))
+      return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), Op1,
+                          Constant::getNullValue(Op1->getType()));
+    if ((ICmpInst::isSigned(Pred) || ICmpInst::isEquality(Pred)) &&
+        match(Op1, m_SDiv(m_Specific(Op0), m_APInt(C))) && C->abs().ugt(1))
+      return new ICmpInst(Pred, Op0,
+                          Constant::getNullValue(Op0->getType()));
+
+    // For udiv: C > 1. Handles EQ/NE, unsigned, and signed predicates.
+    if (match(Op0, m_UDiv(m_Specific(Op1), m_APInt(C))) && C->ugt(1)) {
+      if (ICmpInst::isEquality(Pred))
+        return new ICmpInst(Pred, Op1, Constant::getNullValue(Op1->getType()));
+      if (ICmpInst::isSigned(Pred))
+        return new ICmpInst(ICmpInst::getSwappedPredicate(Pred), Op1,
+                            Constant::getNullValue(Op1->getType()));
+      if (Pred == ICmpInst::ICMP_ULT)
+        return new ICmpInst(ICmpInst::ICMP_NE, Op1,
+                            Constant::getNullValue(Op1->getType()));
+      if (Pred == ICmpInst::ICMP_UGE)
+        return new ICmpInst(ICmpInst::ICMP_EQ, Op1,
+                            Constant::getNullValue(Op1->getType()));
+      if (Pred == ICmpInst::ICMP_ULE)
+        return replaceInstUsesWith(I, Builder.getTrue());
+      if (Pred == ICmpInst::ICMP_UGT)
+        return replaceInstUsesWith(I, Builder.getFalse());
+    }
+    if (match(Op1, m_UDiv(m_Specific(Op0), m_APInt(C))) && C->ugt(1)) {
+      if (ICmpInst::isEquality(Pred))
+        return new ICmpInst(Pred, Op0, Constant::getNullValue(Op0->getType()));
+      if (ICmpInst::isSigned(Pred))
+        return new ICmpInst(Pred, Op0,
+                            Constant::getNullValue(Op0->getType()));
+      if (Pred == ICmpInst::ICMP_ULT)
+        return new ICmpInst(ICmpInst::ICMP_NE, Op0,
+                            Constant::getNullValue(Op0->getType()));
+      if (Pred == ICmpInst::ICMP_UGE)
+        return new ICmpInst(ICmpInst::ICMP_EQ, Op0,
+                            Constant::getNullValue(Op0->getType()));
+      if (Pred == ICmpInst::ICMP_ULE)
+        return replaceInstUsesWith(I, Builder.getTrue());
+      if (Pred == ICmpInst::ICMP_UGT)
+        return replaceInstUsesWith(I, Builder.getFalse());
+    }
+
+    // For lshr: C > 0. Handles EQ/NE, unsigned, and signed predicates.
+    if (match(Op0, m_LShr(m_Specific(Op1), m_APInt(C))) && C->ugt(0)) {
+      if (ICmpInst::isEquality(Pred))
+        return new ICmpInst(Pred, Op1, Constant::getNullValue(Op1->getType()));
+      if (Pred == ICmpInst::ICMP_SLT)
+        return new ICmpInst(ICmpInst::ICMP_SGT, Op1,
+                            Constant::getNullValue(Op1->getType()));
+      if (Pred == ICmpInst::ICMP_SLE)
+        return new ICmpInst(ICmpInst::ICMP_SGT, Op1,
+                            Constant::getAllOnesValue(Op1->getType()));
+      if (Pred == ICmpInst::ICMP_SGT)
+        return new ICmpInst(ICmpInst::ICMP_SLT, Op1,
+                            Constant::getNullValue(Op1->getType()));
+      if (Pred == ICmpInst::ICMP_SGE)
+        return new ICmpInst(ICmpInst::ICMP_SLT, Op1,
+                            Constant::getIntegerValue(Op1->getType(),
+                                                      APInt(C->getBitWidth(), 1)));
+      if (Pred == ICmpInst::ICMP_ULT)
+        return new ICmpInst(ICmpInst::ICMP_NE, Op1,
+                            Constant::getNullValue(Op1->getType()));
+      if (Pred == ICmpInst::ICMP_UGE)
+        return new ICmpInst(ICmpInst::ICMP_EQ, Op1,
+                            Constant::getNullValue(Op1->getType()));
+      if (Pred == ICmpInst::ICMP_ULE)
+        return replaceInstUsesWith(I, Builder.getTrue());
+      if (Pred == ICmpInst::ICMP_UGT)
+        return replaceInstUsesWith(I, Builder.getFalse());
+    }
+    if (match(Op1, m_LShr(m_Specific(Op0), m_APInt(C))) && C->ugt(0)) {
+      if (ICmpInst::isEquality(Pred))
+        return new ICmpInst(Pred, Op0, Constant::getNullValue(Op0->getType()));
+      if (Pred == ICmpInst::ICMP_SLT)
+        return new ICmpInst(ICmpInst::ICMP_SGT, Op0,
+                            Constant::getNullValue(Op0->getType()));
+      if (Pred == ICmpInst::ICMP_SLE)
+        return new ICmpInst(ICmpInst::ICMP_SGT, Op0,
+                            Constant::getAllOnesValue(Op0->getType()));
+      if (Pred == ICmpInst::ICMP_SGT)
+        return new ICmpInst(ICmpInst::ICMP_SLT, Op0,
+                            Constant::getNullValue(Op0->getType()));
+      if (Pred == ICmpInst::ICMP_SGE)
+        return new ICmpInst(ICmpInst::ICMP_SLT, Op0,
+                            Constant::getIntegerValue(Op0->getType(),
+                                                      APInt(C->getBitWidth(), 1)));
+      if (Pred == ICmpInst::ICMP_ULT)
+        return new ICmpInst(ICmpInst::ICMP_NE, Op0,
+                            Constant::getNullValue(Op0->getType()));
+      if (Pred == ICmpInst::ICMP_UGE)
+        return new ICmpInst(ICmpInst::ICMP_EQ, Op0,
+                            Constant::getNullValue(Op0->getType()));
+      if (Pred == ICmpInst::ICMP_ULE)
+        return replaceInstUsesWith(I, Builder.getTrue());
+      if (Pred == ICmpInst::ICMP_UGT)
+        return replaceInstUsesWith(I, Builder.getFalse());
+    }
+
+    // For ashr: C > 0. Handles EQ/NE, SGE, and SLT predicates.
+    if (match(Op0, m_AShr(m_Specific(Op1), m_APInt(C))) && C->ugt(0)) {
+      if (ICmpInst::isEquality(Pred))
+        return new ICmpInst(Pred, Op1, Constant::getNullValue(Op1->getType()));
+      if (Pred == ICmpInst::ICMP_SGE)
+        return new ICmpInst(ICmpInst::ICMP_SLT, Op1,
+                            Constant::getIntegerValue(Op1->getType(),
+                                                      APInt(C->getBitWidth(), 1)));
+      if (Pred == ICmpInst::ICMP_SLT)
+        return new ICmpInst(ICmpInst::ICMP_SGT, Op1,
+                            Constant::getNullValue(Op1->getType()));
+    }
+    if (match(Op1, m_AShr(m_Specific(Op0), m_APInt(C))) && C->ugt(0)) {
+      if (ICmpInst::isEquality(Pred))
+        return new ICmpInst(Pred, Op0, Constant::getNullValue(Op0->getType()));
+      if (Pred == ICmpInst::ICMP_SGE)
+        return new ICmpInst(ICmpInst::ICMP_SLT, Op0,
+                            Constant::getIntegerValue(Op0->getType(),
+                                                      APInt(C->getBitWidth(), 1)));
+      if (Pred == ICmpInst::ICMP_SLT)
+        return new ICmpInst(ICmpInst::ICMP_SGT, Op0,
+                            Constant::getNullValue(Op0->getType()));
+    }
+  }
   if (Value *V = foldMultiplicationOverflowCheck(I))
     return replaceInstUsesWith(I, V);

@@ -7108,6 +7240,70 @@ Instruction *InstCombinerImpl::foldICmpCommutative(ICmpInst::Predicate Pred,
       return foldICmpAddOpConst(X, *C, Pred);
   }

+  {
+    // icmp (X /s C), X
+    Value *X;
+    const APInt *C;
+    if (match(Op0, m_SDiv(m_Value(X), m_APInt(C))) && Op1 == X) {
+      if (!C->isZero() && !C->isOne()) {
+        switch (Pred) {
+        case ICmpInst::ICMP_SLT:
+          return new ICmpInst(ICmpInst::ICMP_SGT, X,
+                              ConstantInt::getNullValue(X->getType()));
+        case ICmpInst::ICMP_SGE:
+          return new ICmpInst(ICmpInst::ICMP_SLE, X,
+                              ConstantInt::getNullValue(X->getType()));
+        case ICmpInst::ICMP_SLE:
+          return replaceInstUsesWith(CxtI,
+                                     ConstantInt::getTrue(CxtI.getType()));
+        case ICmpInst::ICMP_SGT:
+          return replaceInstUsesWith(CxtI,
+                                     ConstantInt::getFalse(CxtI.getType()));
+        case ICmpInst::ICMP_EQ:
+          return new ICmpInst(ICmpInst::ICMP_EQ, X,
+                              ConstantInt::getNullValue(X->getType()));
+        case ICmpInst::ICMP_NE:
+          return new ICmpInst(ICmpInst::ICMP_NE, X,
+                              ConstantInt::getNullValue(X->getType()));
+        default:
+          break;
+        }
+      }
+    }
+  }
+
+  {
+    // icmp (X /u C), X
+    Value *X;
+    const APInt *C;
+    if (match(Op0, m_UDiv(m_Value(X), m_APInt(C))) && Op1 == X) {
+      if (!C->isZero() && !C->isOne()) {
+        switch (Pred) {
+        case ICmpInst::ICMP_ULT:
+          return new ICmpInst(ICmpInst::ICMP_NE, X,
+                              ConstantInt::getNullValue(X->getType()));
+        case ICmpInst::ICMP_UGE:
+          return new ICmpInst(ICmpInst::ICMP_EQ, X,
+                              ConstantInt::getNullValue(X->getType()));
+        case ICmpInst::ICMP_ULE:
+          return replaceInstUsesWith(CxtI,
+                                     ConstantInt::getTrue(CxtI.getType()));
+        case ICmpInst::ICMP_UGT:
+          return replaceInstUsesWith(CxtI,
+                                     ConstantInt::getFalse(CxtI.getType()));
+        case ICmpInst::ICMP_EQ:
+          return new ICmpInst(ICmpInst::ICMP_EQ, X,
+                              ConstantInt::getNullValue(X->getType()));
+        case ICmpInst::ICMP_NE:
+          return new ICmpInst(ICmpInst::ICMP_NE, X,
+                              ConstantInt::getNullValue(X->getType()));
+        default:
+          break;
+        }
+      }
+    }
+  }
+
   // abs(X) >=  X --> true
   // abs(X) u<= X --> true
   // abs(X) <   X --> false

